/**
 * @fileoverview Lightweight Finite State Machine for RazyUI components.
 *
 * Usage:
 *   import { StateMachine } from './shared/StateMachine.js';
 *
 *   const sm = new StateMachine({
 *     initial: 'closed',
 *     states: {
 *       closed: { on: { OPEN: 'opening' } },
 *       opening: { on: { OPENED: 'open' } },
 *       open:   { on: { CLOSE: 'closing' } },
 *       closing: { on: { CLOSED: 'closed' } },
 *     },
 *     effects: {
 *       opening(ctx, payload) { ... },
 *       open(ctx, payload) { ... },
 *       'open:exit'(ctx, payload) { ... },
 *       closing(ctx, payload) { ... },
 *       closed(ctx, payload) { ... },
 *     }
 *   }, contextObject);
 *
 *   sm.send('OPEN');        // closed → opening, runs opening effect
 *   sm.current;             // 'opening'
 *   sm.can('CLOSE');        // false (not valid from 'opening')
 *
 * Effect naming:
 *   - 'stateName'        → entry effect (runs when entering state)
 *   - 'stateName:exit'   → exit effect (runs when leaving state)
 *
 * Context:
 *   A mutable object passed to all effects. Typically stores DOM refs, callbacks,
 *   and a back-reference to the StateMachine itself. The StateMachine injects
 *   `ctx.sm = this` automatically for convenience.
 *
 * @module shared/StateMachine
 */

class StateMachine {
    /** @type {string} */
    #state;

    /** @type {import('./StateMachine').StateMachineConfig} */
    #config;

    /** @type {object} */
    #context;

    /** @type {Array<(next: string, prev: string, event: string) => void>} */
    #listeners = [];

    /**
     * @param {object} config
     * @param {string} config.initial — initial state name
     * @param {Object<string, {on?: Object<string, string>}>} config.states — state definitions
     * @param {Object<string, (ctx: object, payload?: any) => void>} [config.effects] — state effects
     * @param {object} [context={}] — shared context object passed to effects
     */
    constructor(config, context = {}) {
        if (!config?.initial) throw new Error('[StateMachine] config.initial is required');
        if (!config?.states?.[config.initial]) throw new Error(`[StateMachine] initial state "${config.initial}" not found in states`);

        this.#config = Object.freeze({ ...config });
        this.#context = context;
        this.#state = config.initial;

        // Inject self-reference into context
        this.#context.sm = this;
    }

    /** Current state name. */
    get current() {
        return this.#state;
    }

    /**
     * Send an event to attempt a state transition.
     *
     * @param {string} event — the event name (e.g. 'OPEN', 'CLOSE')
     * @param {*} [payload] — optional data passed to effects
     * @returns {string} the state after processing (may be unchanged)
     */
    send(event, payload) {
        const stateConfig = this.#config.states[this.#state];
        if (!stateConfig?.on) return this.#state;

        const next = stateConfig.on[event];
        if (!next || next === this.#state) return this.#state;

        // Validate target state exists
        if (!this.#config.states[next]) {
            console.warn(`[StateMachine] transition target "${next}" not found in states`);
            return this.#state;
        }

        const prev = this.#state;
        this.#state = next;

        // Run exit effect for previous state
        this.#config.effects?.[`${prev}:exit`]?.(this.#context, payload);

        // Run entry effect for new state
        this.#config.effects?.[next]?.(this.#context, payload);

        // Notify listeners
        for (const fn of this.#listeners) {
            try { fn(next, prev, event); }
            catch (e) { console.error('[StateMachine] listener error:', e); }
        }

        return this.#state;
    }

    /**
     * Check if a given event can trigger a transition from the current state.
     *
     * @param {string} event
     * @returns {boolean}
     */
    can(event) {
        return !!this.#config.states[this.#state]?.on?.[event];
    }

    /**
     * Get all valid events from the current state.
     *
     * @returns {string[]}
     */
    get validEvents() {
        const on = this.#config.states[this.#state]?.on;
        return on ? Object.keys(on) : [];
    }

    /**
     * Get all state names.
     *
     * @returns {string[]}
     */
    get allStates() {
        return Object.keys(this.#config.states);
    }

    /**
     * Subscribe to state changes.
     *
     * @param {(next: string, prev: string, event: string) => void} fn
     * @returns {() => void} unsubscribe function
     */
    onChange(fn) {
        this.#listeners.push(fn);
        return () => {
            this.#listeners = this.#listeners.filter(f => f !== fn);
        };
    }

    /**
     * Force-reset to a given state without running effects.
     * Used for initialization or error recovery.
     *
     * @param {string} [state] — state to reset to (defaults to initial state)
     */
    reset(state) {
        const target = state || this.#config.initial;
        if (!this.#config.states[target]) {
            throw new Error(`[StateMachine] reset target "${target}" not found in states`);
        }
        this.#state = target;
    }

    /**
     * Check if the current state is a specific state.
     *
     * @param {string} state
     * @returns {boolean}
     */
    is(state) {
        return this.#state === state;
    }

    /**
     * Check if the current state is any of the given states.
     *
     * @param {...string} states
     * @returns {boolean}
     */
    isAny(...states) {
        return states.includes(this.#state);
    }

    /**
     * Serialize current state for debugging/DevPanel.
     *
     * @returns {{ current: string, validEvents: string[], allStates: string[] }}
     */
    toJSON() {
        return {
            current: this.#state,
            validEvents: this.validEvents,
            allStates: this.allStates,
        };
    }
}

export { StateMachine };
export default StateMachine;
